  @reaper gmem_write, gmem_read, gmem_attach
  @reaper TrackFX_GetCount, TrackFX_GetFXName, TrackFX_SetParam, TrackFX_GetFXGUID
  @reaper GetSetMediaTrackInfo_String
  @reaper CountTracks
  @reaper GetTrack
